Let $C$ be a pointed rational cone in $V$. 
 If $C=C_0=\{0\}$ is the trivial cone, we set
\begin{equation*}
R(C_0):=T(C_0).
\end{equation*}

Otherwise, if $\dim(C)\geq 1$, we assume we have constructed all regions $R(K)$ for faces $K<C$. 
Let $X_K^C$ be the set of all points $x$ in $L(K)$ that satisfy:

\begin{compactenum}[(I)]
\item \label{Ppt:Inside}  $x+R(K) \subseteq int(M^\vee)$ \hfill for all rays $M \leq C$ with $M\nleq K$\; \;\,  and
\item \label{Ppt:Nonintersect} $\left( x+ R(K) \right) \cap \left(x'+ R(K')\right) = \varnothing$ \; \hfill  \; for all $K'<C$,   with
 \raggedleft{ $K'$ \textnormal{ incomparable to } $K$  and $x'\in L(K')$.}   
\end{compactenum}
Then  we define the region $R(C)$  of $C$ as
\begin{equation} \label{Eqn:region}
R(C):=\left(V\backslash  \bigcup_{K<C} \left(  X_K^C+R(K)\right) \right) \cap \left( T(C) + \lin(C)\right) \cap \upper {C^\vee}.
\end{equation}




